const rows = $input.all();

const quotes = rows.map(({ json }, index) => ({
  id: json.leadId || json.id || json.Lead_ID || `lead-${index + 1}`,
  leadId: json.leadId || json.id || json.Lead_ID || `lead-${index + 1}`,
  nombre: json.nombre || json.name || json.Nombre || 'Sin nombre',
  empresa: json.empresa || json.company || json.Empresa || 'Empresa no especificada',
  email: json.email || json.Prospect_Email || json.Email || '',
  servicio: json.servicio || json.service || json.Servicio || 'Sin servicio',
  monto: json.monto || json.amount || json.Monto || '$0',
  industria: json.industria || json.industry || json.Industria || 'General',
  estado: json.Estado || json.estado || json.status || 'Pendiente',
  briefUrl: json.Brief_URL || json.briefUrl || '',
  briefToken: json.Brief_Token || json.briefToken || ''
}));

return [{ json: { quotes } }];
